// Search for orders by name and within a specific date range
const findResult = orders.find({
  name: "Lemony Snicket",
  date: {
    $gte: new Date(new Date().setHours(00, 00, 00)),
    $lt: new Date(new Date().setHours(23, 59, 59)),
  },
});

for await (const doc of findResult) {
  console.log(doc);
}
